for (var y=0; y<ymData.length; y++) {
  var v=Math.round(ymData[y].metrics[0]);
  ymT+=v;
  var src=(ymData[y].dimensions[0].name||'');
  if (src.indexOf('Search')!==-1) ymO+=v;
  if (src.indexOf('Direct')!==-1) ymD+=v;
}

// PostgreSQL SEO Health
